130	bool ULFPGameInstance::SpendGold(int32 Amount)
131	{
132		if (Amount < 0)
133		{
134			return false;
135		}
136	
137		if (!CanAffordGold(Amount))
138		{
139			UE_LOG(LogTemp, Warning, TEXT("金币不足: 需要 %d, 当前 %d"), Amount, Gold);
140			return false;
141		}
142	
143		Gold -= Amount;
144		UE_LOG(LogTemp, Log, TEXT("金币变动: -%d, 当前: %d"), Amount, Gold);
145		return true;
146	}
