234	bool ULFPGameInstance::TryAddUnit(const FLFPUnitEntry& Unit)
235	{
236		if (!Unit.IsValid()) return false;
237	
238		if (!IsPartyFull())
239		{
240			PartyUnits.Add(Unit);
241			UE_LOG(LogTemp, Log, TEXT("单位 %s 加入出战队伍（%d/%d）"), *Unit.TypeID.ToString(), PartyUnits.Num(), MaxPartySize);
242			return true;
243		}
244		if (!IsReserveFull())
245		{
246			ReserveUnits.Add(Unit);
247			UE_LOG(LogTemp, Log, TEXT("单位 %s 加入备战营（%d/%d）"), *Unit.TypeID.ToString(), ReserveUnits.Num(), MaxReserveSize);
248			return true;
249		}
250		return false;
251	}
