290	
291	TArray<FLFPUnitEntry> ULFPGameInstance::GetMergeablePairs() const
292	{
293		// 统计每个 TypeID 的出现次数
294		TMap<FName, int32> CountMap;
295	
296		for (const FLFPUnitEntry& Unit : PartyUnits)
297		{
298			if (Unit.IsValid())
299			{
300				CountMap.FindOrAdd(Unit.TypeID, 0)++;
301			}
302		}
303		for (const FLFPUnitEntry& Unit : ReserveUnits)
304		{
305			if (Unit.IsValid())
306			{
307				CountMap.FindOrAdd(Unit.TypeID, 0)++;
308			}
309		}
310	
311		// 筛选出现 >= 2 次且注册表中有进化目标的 TypeID
312		TArray<FLFPUnitEntry> Result;
313		for (const auto& Pair : CountMap)
314		{
315			if (Pair.Value >= 2 && UnitRegistry && UnitRegistry->CanEvolve(Pair.Key))
316			{
317				FLFPUnitEntry Entry;
318				Entry.TypeID = Pair.Key;
319				Entry.Tier = UnitRegistry->GetUnitTier(Pair.Key);
320				Result.Add(Entry);
321			}
322		}
323	
324		return Result;
325	}
