587	void ALFPWorldMapPlayerController::OpenShop(ALFPWorldMapNode* ShopNode, bool bReturnToTownOnClose)
588	{
589		if (!ShopNode || !ShopWidgetClass)
590		{
591			return;
592		}
593	
594		ULFPGameInstance* GI = Cast<ULFPGameInstance>(GetGameInstance());
595		if (!GI || ShopNode->ShopID == NAME_None)
596		{
597			UE_LOG(LogTemp, Warning, TEXT("商店节点 %d: ShopID 无效"), ShopNode->NodeID);
598			if (bReturnToTownOnClose && TownWidget && TownWidget->IsInViewport())
599			{
600				TownWidget->SetVisibility(ESlateVisibility::Visible);
601			}
602			return;
603		}
604	
605		FLFPShopDefinition ShopDefinition;
606		if (!GI->FindShopDefinition(ShopNode->ShopID, ShopDefinition))
607		{
608			UE_LOG(LogTemp, Warning, TEXT("商店配置不存在: %s"), *ShopNode->ShopID.ToString());
609			if (bReturnToTownOnClose && TownWidget && TownWidget->IsInViewport())
610			{
611				TownWidget->SetVisibility(ESlateVisibility::Visible);
612			}
613			return;
614		}
615	
616		bReturnToTownAfterShopClose = bReturnToTownOnClose;
617	
618		if (!ShopWidget)
619		{
620			ShopWidget = CreateWidget<ULFPShopWidget>(this, ShopWidgetClass);
621			if (ShopWidget)
622			{
623				ShopWidget->OnClosed.AddDynamic(this, &ALFPWorldMapPlayerController::OnShopWidgetClosed);
624				ShopWidget->AddToViewport();
625			}
626		}
627		else
628		{
629			ShopWidget->SetVisibility(ESlateVisibility::Visible);
630			ShopWidget->AddToViewport();
631		}
632	
633		if (ShopWidget)
634		{
635			ShopWidget->Setup(GI, ShopNode->ShopID, ShopDefinition);
636		}
637	}
